-- Cleaned schema: removed autogenerated fk{n}_ columns/constraints and added real FK constraints from *_FK columns

CREATE TABLE Company(
                        Company_ID	INTEGER NOT NULL,
                        Name	VARCHAR(255) NOT NULL,
                        Slug	VARCHAR(100) NOT NULL,
                        RegistrationNumber	VARCHAR(100) NOT NULL,
                        ContactEmail	VARCHAR(255) NOT NULL,
                        ContactPhone	VARCHAR(50) NOT NULL,
                        WebSiteUrl	VARCHAR(255) NOT NULL,
                        CreatedAt	TIMESTAMP(0) NOT NULL,
                        UpdatedAt	TIMESTAMP(0),
                        DeletedAt	TIMESTAMP(0),
                        DeActivatedAt	TIMESTAMP(0),
                        CreatedByAppUser_ID_FK	INTEGER NOT NULL,
                        CONSTRAINT	pk_Company PRIMARY KEY (Company_ID)
);

CREATE TABLE CompanySettings(
                                CompanySettings_ID	INTEGER NOT NULL,
                                DefaultNoRepeatWeeks	INTEGER NOT NULL,
                                SelectionDeadlineDaysBeforeDelivery	INTEGER NOT NULL,
                                AllowAutoSelection	BOOLEAN NOT NULL,
                                AllowPauseSubscription	BOOLEAN NOT NULL,
                                AllowSkipWeek	BOOLEAN NOT NULL,
                                MinimumSubscriptionWeeks	INTEGER NOT NULL,
                                MaxDeliveryAttempts	INTEGER NOT NULL,
                                AllowRedeliveryAfterFailure	BOOLEAN NOT NULL,
                                ComplaintEscalationThreshold	INTEGER NOT NULL,
                                ComplaintEscalationDaysWindow	INTEGER NOT NULL,
                                AutoPrioritizeFreshestStock	BOOLEAN NOT NULL,
                                AutoAssignEarliestSlot	BOOLEAN NOT NULL,
                                Company_ID_FK	INTEGER NOT NULL,
                                UpdatedAt	TIMESTAMP(0),
                                UpdatedByAppUser_ID_FK	INTEGER NOT NULL,
                                UNIQUE(Company_ID_FK),
                                CONSTRAINT	pk_CompanySettings PRIMARY KEY (CompanySettings_ID)
);

CREATE TABLE Customer(
                         Customer_ID	INTEGER NOT NULL,
                         Email	VARCHAR(255) NOT NULL,
                         FirstName	VARCHAR(100) NOT NULL,
                         LastName	VARCHAR(100) NOT NULL,
                         PhoneNumber	VARCHAR(50),
                         IsActive	BOOLEAN NOT NULL,
                         AddressLine	VARCHAR(255) NOT NULL,
                         City	VARCHAR(100) NOT NULL,
                         PostalCode	VARCHAR(20) NOT NULL,
                         Country	VARCHAR(100) NOT NULL,
                         Company_ID_FK	INTEGER NOT NULL,
                         CreatedAt	TIMESTAMP(0) NOT NULL,
                         UpdatedAt	TIMESTAMP(0),
                         DeletedAt	TIMESTAMP(0),
                         CONSTRAINT	pk_Customer PRIMARY KEY (Customer_ID)
);

CREATE TABLE MealSubscription(
                                 MealSubscription_ID	INTEGER NOT NULL,
