ALTER TABLE CompanySettings ALTER COLUMN AllowSkipWeek SET DEFAULT TRUE;
ALTER TABLE CompanySettings ALTER COLUMN MinimumSubscriptionWeeks SET DEFAULT 0;
ALTER TABLE CompanySettings ALTER COLUMN MaxDeliveryAttempts SET DEFAULT 2;
ALTER TABLE CompanySettings ALTER COLUMN AllowRedeliveryAfterFailure SET DEFAULT TRUE;
ALTER TABLE CompanySettings ALTER COLUMN ComplaintEscalationThreshold SET DEFAULT 2;
ALTER TABLE CompanySettings ALTER COLUMN ComplaintEscalationDaysWindow SET DEFAULT 30;
ALTER TABLE CompanySettings ALTER COLUMN AutoPrioritizeFreshestStock SET DEFAULT TRUE;
ALTER TABLE CompanySettings ALTER COLUMN AutoAssignEarliestSlot SET DEFAULT FALSE;

-- Box constraints (meals/people)
ALTER TABLE Box ADD CONSTRAINT ck_Box_MealsCount CHECK (MealsCount IN (3,4,5));
ALTER TABLE Box ADD CONSTRAINT ck_Box_PeopleCount CHECK (PeopleCount IN (2,4));

-- Rating score constraint
ALTER TABLE Rating ADD CONSTRAINT ck_Rating_Score CHECK (Score BETWEEN 1 AND 5);

-- Delivery window validity constraints
ALTER TABLE DeliveryWindow ADD CONSTRAINT ck_DeliveryWindow_DayOfWeek CHECK (DayOfWeek BETWEEN 1 AND 7);
ALTER TABLE DeliveryWindow ADD CONSTRAINT ck_DeliveryWindow_TimeRange CHECK (StartTime < EndTime);

-- NutritionalInfo non-negative constraints (per serving)
ALTER TABLE NutritionalInfo
    ADD CONSTRAINT ck_NutritionalInfo_NonNegative CHECK (
        CaloriesKcal >= 0
            AND ProteinG >= 0
            AND CarbsG >= 0
            AND FatG >= 0
            AND (FiberG IS NULL OR FiberG >= 0)
            AND (SodiumMg IS NULL OR SodiumMg >= 0)
        );

-- Date range constraints
ALTER TABLE BoxPrice
    ADD CONSTRAINT ck_BoxPrice_DateRange CHECK (
        ValidFrom IS NULL OR ValidTo IS NULL OR ValidFrom <= ValidTo
        );
ALTER TABLE PlatformSubscription
    ADD CONSTRAINT ck_PlatformSubscription_DateRange CHECK (
        ValidFrom IS NULL OR ValidTo IS NULL OR ValidFrom <= ValidTo
        );
